import os
import subprocess
import sys

def backup_directory(directory_path, format):
    # Validate directory path
    if not os.path.isdir(directory_path):
        raise ValueError("Invalid directory path")

    # Validate format
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format not in allowed_formats:
        raise ValueError("Unsupported format. Choose from: tar.gz, tar.bz2, zip, 7z")

    # Construct the output file name
    base_name = os.path.basename(os.path.normpath(directory_path))
    output_file = f"{base_name}.{format}"

    # Perform the backup based on the format
    try:
        if format == 'tar.gz':
            subprocess.run(['tar', '-czf', output_file, '-C', directory_path, '.'], check=True)
        elif format == 'tar.bz2':
            subprocess.run(['tar', '-cjf', output_file, '-C', directory_path, '.'], check=True)
        elif format == 'zip':
            subprocess.run(['zip', '-r', output_file, '.', '-i', '*'], cwd=directory_path, check=True)
        elif format == '7z':
            subprocess.run(['7z', 'a', output_file, '.'], cwd=directory_path, check=True)
    except subprocess.CalledProcessError as e:
        print(f"An error occurred: {e}")
        sys.exit(1)

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
